import { BrowserRouter, Routes, Route } from "react-router-dom";
import Navbar from './components/Navbar.tsx';
import ShapeList from './pages/ShapeList.tsx';
import ShapeForm from './pages/ShapeForm.tsx';
import ComplexShapeList from "./pages/ComplexShapeList";
import ComplexShapeForm from "./pages/ComplexShapeForm";


function App() {

    return (

        <BrowserRouter>

            <Navbar />

            <Routes>

                <Route

                    path="/"

                    element={<ShapeList />}

                />

                <Route

                    path="/new"

                    element={<ShapeForm />}

                />
 <Route path="/edit/:id" element={<ShapeForm />} />
 <Route path="/complex" element={<ComplexShapeList />} />
<Route path="/complex/new" element={<ComplexShapeForm />} />
            </Routes>

        </BrowserRouter>

    );

}

export default App;
